// frontend/src/components/admin/ReportsAnalytics.js
import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import './Admin.css';

const ReportsAnalytics = () => {
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [dateRange, setDateRange] = useState('month');
    const [reportData, setReportData] = useState(null);
    const [exportFormat, setExportFormat] = useState('csv');
    const [exportType, setExportType] = useState('users');

    useEffect(() => {
        loadReportData();
    }, [dateRange]);

    const loadReportData = async () => {
        setLoading(true);
        setError('');
        try {
            console.log(`📊 Loading ${dateRange} report data...`);
            const response = await api.get(`/admin/reports?range=${dateRange}`);

            if (response.data.success) {
                console.log('✅ Report data loaded:', response.data.data);
                setReportData(response.data.data);
            } else {
                setError('Failed to load report data');
            }
        } catch (error) {
            console.error('❌ Error loading report data:', error);
            setError('Failed to load report data. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleExport = async () => {
        try {
            console.log(`📥 Exporting ${exportType} data as ${exportFormat}...`);

            const response = await api.get(`/admin/export?format=${exportFormat}&type=${exportType}&range=${dateRange}`, {
                responseType: exportFormat === 'csv' ? 'blob' : 'json'
            });

            if (exportFormat === 'csv') {
                // Handle CSV download
                const url = window.URL.createObjectURL(new Blob([response.data]));
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', `export-${exportType}-${dateRange}-${new Date().toISOString().split('T')[0]}.csv`);
                document.body.appendChild(link);
                link.click();
                link.remove();
            } else {
                // Handle JSON/Excel data
                const dataStr = JSON.stringify(response.data, null, 2);
                const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
                const link = document.createElement('a');
                link.href = dataUri;
                link.setAttribute('download', `export-${exportType}-${dateRange}-${new Date().toISOString().split('T')[0]}.json`);
                document.body.appendChild(link);
                link.click();
                link.remove();
            }

            alert(`✅ Export completed successfully!`);
        } catch (error) {
            console.error('❌ Error exporting data:', error);
            alert('Failed to export data. Please try again.');
        }
    };

    const formatCurrency = (amount) => {
        if (!amount) return 'R0';
        return `R${amount.toLocaleString()}`;
    };

    const formatNumber = (num) => {
        if (!num) return '0';
        return num.toLocaleString();
    };

    const formatPercentage = (value, total) => {
        if (!total || total === 0) return '0%';
        return `${((value / total) * 100).toFixed(1)}%`;
    };

    const getRangeLabel = () => {
        switch(dateRange) {
            case 'today': return 'Today';
            case 'week': return 'This Week';
            case 'month': return 'This Month';
            case 'quarter': return 'This Quarter';
            case 'year': return 'This Year';
            default: return 'All Time';
        }
    };

    if (loading) {
        return (
            <div className="reports-tab">
                <div className="loading-container">
                    <div className="loading-spinner">Loading reports data...</div>
                </div>
            </div>
        );
    }

    const summary = reportData?.summary || {};
    const userGrowth = reportData?.user_growth || [];
    const jobTrends = reportData?.job_trends || [];
    const revenue = reportData?.revenue || [];
    const categories = reportData?.categories || [];
    const workers = reportData?.workers || [];
    const clients = reportData?.clients || [];
    const vouchers = reportData?.vouchers || [];
    const peakHours = reportData?.peak_hours || [];
    const townshipPerformance = reportData?.township_performance || [];

    return (
        <div className="reports-tab">
            <div className="management-header">
                <h1>📈 Reports & Analytics</h1>
                <div className="report-actions">
                    <select 
                        value={dateRange} 
                        onChange={(e) => setDateRange(e.target.value)}
                        className="range-select"
                    >
                        <option value="today">Today</option>
                        <option value="week">This Week</option>
                        <option value="month">This Month</option>
                        <option value="quarter">This Quarter</option>
                        <option value="year">This Year</option>
                        <option value="all">All Time</option>
                    </select>

                    <select 
                        value={exportType} 
                        onChange={(e) => setExportType(e.target.value)}
                        className="type-select"
                    >
                        <option value="users">Users</option>
                        <option value="jobs">Jobs</option>
                        <option value="payments">Payments</option>
                        <option value="vouchers">Vouchers</option>
                        <option value="reviews">Reviews</option>
                    </select>

                    <select 
                        value={exportFormat} 
                        onChange={(e) => setExportFormat(e.target.value)}
                        className="format-select"
                    >
                        <option value="csv">CSV</option>
                        <option value="excel">Excel (JSON)</option>
                        <option value="pdf">PDF (HTML)</option>
                    </select>

                    <button className="btn-export" onClick={handleExport}>
                        📥 Export
                    </button>

                    <button className="btn-refresh" onClick={loadReportData}>
                        🔄 Refresh
                    </button>
                </div>
            </div>

            {error && <div className="error-message">{error}</div>}

            {/* Summary Cards */}
            <div className="summary-cards">
                <div className="summary-card">
                    <span className="summary-icon">📅</span>
                    <div className="summary-info">
                        <span className="summary-label">Report Period</span>
                        <span className="summary-value">{getRangeLabel()}</span>
                    </div>
                </div>
                <div className="summary-card">
                    <span className="summary-icon">⏱️</span>
                    <div className="summary-info">
                        <span className="summary-label">Generated</span>
                        <span className="summary-value">
                            {new Date(summary.generated_at).toLocaleString()}
                        </span>
                    </div>
                </div>
            </div>

            {/* Key Metrics */}
            <div className="metrics-grid">
                <div className="metric-card">
                    <h3>User Growth</h3>
                    <div className="metric-big">{formatNumber(userGrowth.reduce((acc, d) => acc + d.new_users, 0))}</div>
                    <div className="metric-sub">New Users</div>
                    <div className="metric-breakdown">
                        <span>👷 Workers: {formatNumber(userGrowth.reduce((acc, d) => acc + d.new_workers, 0))}</span>
                        <span>🏠 Clients: {formatNumber(userGrowth.reduce((acc, d) => acc + d.new_clients, 0))}</span>
                    </div>
                </div>

                <div className="metric-card">
                    <h3>Job Activity</h3>
                    <div className="metric-big">{formatNumber(jobTrends.reduce((acc, d) => acc + d.total_jobs, 0))}</div>
                    <div className="metric-sub">Total Jobs</div>
                    <div className="metric-breakdown">
                        <span>✅ Completed: {formatNumber(jobTrends.reduce((acc, d) => acc + d.completed_jobs, 0))}</span>
                        <span>⚡ Urgent: {formatNumber(jobTrends.reduce((acc, d) => acc + d.urgent_jobs, 0))}</span>
                    </div>
                </div>

                <div className="metric-card">
                    <h3>Revenue</h3>
                    <div className="metric-big">{formatCurrency(revenue.reduce((acc, d) => acc + d.total_revenue, 0))}</div>
                    <div className="metric-sub">Total Revenue</div>
                    <div className="metric-breakdown">
                        <span>💳 Fees: {formatCurrency(revenue.reduce((acc, d) => acc + d.total_fees, 0))}</span>
                        <span>📊 Avg: {formatCurrency(
                            revenue.reduce((acc, d) => acc + d.total_revenue, 0) / 
                            Math.max(revenue.reduce((acc, d) => acc + d.transaction_count, 0), 1)
                        )}</span>
                    </div>
                </div>
            </div>

            {/* User Growth Chart */}
            {userGrowth.length > 0 && (
                <div className="report-card">
                    <h3>User Growth Over Time</h3>
                    <div className="chart-container">
                        <div className="bar-chart">
                            {userGrowth.map((item, index) => (
                                <div key={index} className="bar-group">
                                    <div className="bar-stack">
                                        <div 
                                            className="bar workers-bar" 
                                            style={{ height: `${Math.min(item.new_workers * 5, 100)}px` }}
                                            title={`Workers: ${item.new_workers}`}
                                        ></div>
                                        <div 
                                            className="bar clients-bar" 
                                            style={{ height: `${Math.min(item.new_clients * 5, 100)}px` }}
                                            title={`Clients: ${item.new_clients}`}
                                        ></div>
                                    </div>
                                    <span className="bar-label">{item.period}</span>
                                </div>
                            ))}
                        </div>
                        <div className="chart-legend">
                            <span className="legend-item workers">👷 Workers</span>
                            <span className="legend-item clients">🏠 Clients</span>
                        </div>
                    </div>
                </div>
            )}

            {/* Revenue Chart */}
            {revenue.length > 0 && (
                <div className="report-card">
                    <h3>Revenue Trend</h3>
                    <div className="chart-container">
                        <div className="line-chart">
                            {revenue.map((item, index) => (
                                <div key={index} className="data-point-group">
                                    <div 
                                        className="data-point" 
                                        style={{ bottom: `${Math.min(item.total_revenue / 100, 150)}px` }}
                                        title={`R${item.total_revenue}`}
                                    >
                                        <span className="point-value">R{item.total_revenue}</span>
                                    </div>
                                    <span className="point-label">{item.period}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* Category Performance */}
            {categories.length > 0 && (
                <div className="report-card">
                    <h3>Category Performance</h3>
                    <div className="categories-table">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Category</th>
                                    <th>Total Jobs</th>
                                    <th>Completed</th>
                                    <th>Success Rate</th>
                                    <th>Avg Budget</th>
                                    <th>Avg Rating</th>
                                </tr>
                            </thead>
                            <tbody>
                                {categories.map((cat, index) => (
                                    <tr key={index}>
                                        <td><strong>{cat.category}</strong></td>
                                        <td>{cat.total_jobs}</td>
                                        <td>{cat.completed}</td>
                                        <td>
                                            <div className="progress-bar-small">
                                                <div 
                                                    className="progress-fill" 
                                                    style={{ width: `${(cat.completed / cat.total_jobs) * 100}%` }}
                                                ></div>
                                                <span>{((cat.completed / cat.total_jobs) * 100).toFixed(1)}%</span>
                                            </div>
                                        </td>
                                        <td>R{cat.avg_budget?.toFixed(0)}</td>
                                        <td>
                                            <span className="rating-stars">
                                                {'⭐'.repeat(Math.round(cat.avg_rating || 0))}
                                                <span>({(cat.avg_rating || 0).toFixed(1)})</span>
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Top Workers */}
            {workers.length > 0 && (
                <div className="report-card">
                    <h3>Top Performing Workers</h3>
                    <div className="workers-table">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th>Worker</th>
                                    <th>Township</th>
                                    <th>Primary Skill</th>
                                    <th>Rating</th>
                                    <th>Jobs Completed</th>
                                    <th>Cancellation Rate</th>
                                </tr>
                            </thead>
                            <tbody>
                                {workers.slice(0, 10).map((worker, index) => (
                                    <tr key={index}>
                                        <td><strong>{worker.name}</strong></td>
                                        <td>{worker.township || 'N/A'}</td>
                                        <td>{worker.primary_skill || 'N/A'}</td>
                                        <td>
                                            <span className="rating-value">
                                                {worker.rating?.toFixed(1) || '0.0'} ⭐
                                            </span>
                                        </td>
                                        <td>{worker.completed_jobs || 0}</td>
                                        <td>
                                            <span className={`cancellation-rate ${worker.cancellation_rate > 10 ? 'high' : 'low'}`}>
                                                {worker.cancellation_rate?.toFixed(1) || '0'}%
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Peak Hours */}
            {peakHours.length > 0 && (
                <div className="report-card half-width">
                    <h3>Peak Activity Hours</h3>
                    <div className="hours-chart">
                        {peakHours.map((hour, index) => (
                            <div key={index} className="hour-row">
                                <span className="hour-label">{hour.hour}:00</span>
                                <div className="hour-bar-container">
                                    <div 
                                        className="hour-bar" 
                                        style={{ width: `${(hour.job_count / Math.max(...peakHours.map(h => h.job_count))) * 100}%` }}
                                    >
                                        <span className="hour-count">{hour.job_count} jobs</span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Township Performance */}
            {townshipPerformance.length > 0 && (
                <div className="report-card half-width">
                    <h3>Township Performance</h3>
                    <div className="township-list">
                        {townshipPerformance.map((town, index) => (
                            <div key={index} className="township-stat">
                                <div className="township-header">
                                    <span className="township-name">{town.township}</span>
                                    <span className="township-rate">{town.completion_rate}%</span>
                                </div>
                                <div className="progress-bar">
                                    <div 
                                        className="progress-fill" 
                                        style={{ width: `${town.completion_rate}%` }}
                                    ></div>
                                </div>
                                <div className="township-details">
                                    <span>{town.completed}/{town.total_jobs} jobs</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Voucher Report */}
            {vouchers.length > 0 && (
                <div className="report-card">
                    <h3>Voucher Usage Report</h3>
                    <div className="voucher-stats">
                        {vouchers.map((voucher, index) => (
                            <div key={index} className="voucher-stat-card">
                                <h4>{voucher.voucher_type}</h4>
                                <div className="voucher-numbers">
                                    <div className="voucher-number">
                                        <span className="number-label">Issued</span>
                                        <span className="number-value">{voucher.total_issued}</span>
                                    </div>
                                    <div className="voucher-number">
                                        <span className="number-label">Active</span>
                                        <span className="number-value">{voucher.active}</span>
                                    </div>
                                    <div className="voucher-number">
                                        <span className="number-label">Used</span>
                                        <span className="number-value">{voucher.used}</span>
                                    </div>
                                    <div className="voucher-number">
                                        <span className="number-label">Total Value</span>
                                        <span className="number-value">R{voucher.total_value}</span>
                                    </div>
                                </div>
                                <div className="usage-bar">
                                    <div 
                                        className="usage-fill" 
                                        style={{ width: `${(voucher.used / voucher.total_issued) * 100}%` }}
                                    ></div>
                                </div>
                                <span className="usage-label">
                                    {((voucher.used / voucher.total_issued) * 100).toFixed(1)}% utilized
                                </span>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* No Data Message */}
            {!userGrowth.length && !jobTrends.length && !revenue.length && (
                <div className="no-data-container">
                    <div className="no-data-icon">📊</div>
                    <h3>No Data Available</h3>
                    <p>There is no data available for the selected period.</p>
                    <button onClick={loadReportData} className="btn-refresh">
                        🔄 Try Again
                    </button>
                </div>
            )}
        </div>
    );
};

export default ReportsAnalytics;
